#include <stdio.h>
int floorSqrt(int n) {
    int ans = 0;
    for (int i = 1; i <= n; i++) {
        if ((long long)i * i <= n) {
            ans = i;
        } else {
            break;
        }
    }
    return ans;
}

int main() {
    int n = 27;
    printf("%d\n", floorSqrt(n));
    return 0;
}

